#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=5e5+5;
int a[MAXN],t[MAXN<<2],n,m,lz[MAXN<<2];
void pushup(int o)
{
	t[o]=t[o*2]+t[o*2+1];
}
void pushdown(int o,int l,int r)
{

	int mid=(l+r)/2;
	t[o*2]+=lz[o]*(mid-l+1);
	t[o*2+1]+=lz[o]*(r-mid);
	lz[o*2+1]+=lz[o];
	lz[o*2]+=lz[o];
	lz[o]=0;
}
void build(int l,int r,int o)
{
	if(l==r)
	{
		t[o]=a[l];
		return;
	}
	int mid=(l+r)/2;
	build(l,mid,o*2);
	build(mid+1,r,o*2+1);
	pushup(o);
}
void add(int s,int e,int k,int l=1,int r=n,int o=1)
{
	if(s<=l&&e>=r)
	{
		t[o]+=(r-l+1)*k;
		lz[o]+=k;
		return;
	}
	pushdown(o,l,r);
	int mid=(l+r)/2;
	if(mid>=s)add(s,e,k,l,mid,o*2);
	if(mid+1<=e)add(s,e,k,mid+1,r,o*2+1);
	pushup(o);
}
int query(int s,int e,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		return t[o];
	}
	pushdown(o,l,r);
	int mid=(l+r)/2,sum=0;
	if(s<=mid)sum+=query(s,e,l,mid,o*2);
	if(mid+1<=e)sum+=query(s,e,mid+1,r,o*2+1);
	pushup(o);
	return sum;
}
signed main(void)
{

    //freopen(".in","r",stdin);
