	IOS
	cin>>n>>m;
    FOR(i,1,n)a[i]=0;
	build(1,n,1);
	FOR(i,1,m)
	{
		int x,y;
        char cmd;
		cin>>cmd>>x>>y;
		if(cmd=='x')
		{
			add(x,x,y);
		}
		else
		{
			cout<<query(x,y)<<'\n';
		}
	}
    return false;
}
